- (void)handlePopupDismiss {
    UITabBarController *rootVc = (UITabBarController *)[WBAppManager getUIApplicationRootViewController];
    NSParameterAssert([rootVc isKindOfClass:[UITabBarController class]]);
    UINavigationController *navVc = rootVc.selectedViewController;
    NSParameterAssert([navVc isKindOfClass:[UINavigationController class]]);
    if (navVc.viewControllers[0] == self && !self.presentedViewController) {
        self.vappLaunching = false;
    }
}

#pragma mark - Error Dialogs

- (void)showNotVIPBottomPopup:(WBVAppModel *)vapp launchBlock:(void(^)(void))launchBlock {
    NSString *content;
    if (WBSettingManager.sharedManager.TrialRemindMsg) {
        content = WBSettingManager.sharedManager.TrialRemindMsg;
    } else {
        content = @"免费用户的使用时长将受到限制，成为会员即可无限畅用";
    }
    [WBAlertPopViewController alertWithTitle:@"温馨提示" content:content keyWords:nil confirmText:@"开通会员" cancelText:@"我再想想" confirmAction:^{
        [WBMainViewController presentVipPageFromPageSource:@"trial1"];
        self.vappLaunching = false;
    } cancelAction:^{
        // on cancel, do direct launch
        launchBlock();
    }];
}


- (void)showRunOutOfFreeTimeBottomPopup {
    NSString *content;
    if (WBSettingManager.sharedManager.TrialOverMsg) {
        content = WBSettingManager.sharedManager.TrialOverMsg;
    } else {
        content = @"您当日的免费时长已用完，成为会员即可无限畅用";
    }
    self.vappLaunching = false;
    [WBAlertPopViewController alertWithTitle:@"温馨提示" content:content keyWords:nil confirmText:@"开通会员" cancelText:@"我再想想" confirmAction:^{
        [WBMainViewController presentVipPageFromPageSource:@"trial0"];
    } cancelAction:^{

    }];
}

+ (void)showVIPOnlyFeatureBottomPopup:(NSString *)source {
    [WBAlertPopViewController alertWithTitle:@"温馨提示" content:@"该功能为会员专享，成为会员后畅享" keyWords:nil confirmText:@"开通会员" cancelText:@"我再想想" confirmAction:^{
        [WBMainViewController presentVipPageFromPageSource:source];
    } cancelAction:^{

    }];
}

- (void)showPasswordView:(WBVAppModel *)vapp successBlock:(void(^)(void))block failBlock:failBlock {
    WBPasswordViewController *passwordVc = [WBPasswordViewController new];
    passwordVc.firstSet = FALSE;
    passwordVc.vapp = vapp;
    passwordVc.type = WBPasswordViewControllerTypeEntry;
    passwordVc.bioEnable = true;
    passwordVc.successBlock = block;
    passwordVc.failBlock = failBlock;
    [self.navigationController pushViewController:passwordVc animated:YES];
